const items = $input.all();
const trigger = $node["Webhook"].json.body || {};

// Helper to unwrap Firestore REST values
const unwrap = (val) => {
  if (!val) return null;
  if (val.stringValue) return val.stringValue;
  if (val.timestampValue) return val.timestampValue;
  if (val.integerValue) return parseInt(val.integerValue);
  if (val.booleanValue !== undefined) return val.booleanValue;
  return null;
};

const sessionsMap = {};

items.forEach(item => {
  const doc = item.json.document;
  if (!doc || !doc.fields) return;

  const fields = doc.fields;
  const chatInput = unwrap(fields.message);
  const message = unwrap(fields.bot_response);
  const date = unwrap(fields.timestamp);
  const sessionKey = unwrap(fields.session_id);

  if (!sessionKey) return;

  if (!sessionsMap[sessionKey]) sessionsMap[sessionKey] = [];

  const formattedMsg = `[${new Date(date).toLocaleString('es-AR')}]\n` +
    `USUARIO: ${chatInput || '(sin entrada)'}\n` +
    `BOT: ${message || '(sin respuesta)'}\n` +
    `---`;

  sessionsMap[sessionKey].push(formattedMsg);
});

const sessionsArray = Object.entries(sessionsMap).map(([sessionId, msgs]) => ({
  sessionId,
  fullConversation: `# CONVERSACIÓN ${sessionId}\n\n${msgs.join('\n')}`
}));

return {
  json: {
    sessions: sessionsArray,
    fullConversation: sessionsArray.length > 0 
      ? sessionsArray.map(s => s.fullConversation).join('\n\n')
      : "No se encontraron logs de chat para los criterios seleccionados.",
    type: trigger.type,
    customPrompt: trigger.customPrompt || '',
    sessionIds: trigger.sessionIds || []
  }
};
